import React from 'react'

const Taskcard = ({ task }) => {
    return (
        <>
            <div className='task-card'>
                <div className='task-title'>
                    {task.title}
                </div>
                <div className='task-icons'>
                    <div className='sub-icon'>
                        <button className='icon-button'>
                        <img className='icon-img' className='icon' src='/assets/add.png' alt="Add" />
                        </button>
                    </div>
                    <div className='sub-icon'>
                        <button className='icon-button'>
                        <img className='icon-img' src='/assets/edit.png'></img>
                        </button>
                    </div>
                    <div className='sub-icon'>
                        <button className='icon-button'>
                        <img className='icon-img' src='./assets/delete.png'></img>
                        </button>
                    </div>
                </div>
            </div>
            <Stylesheet />
        </>
    )
}

const Stylesheet = () => {
    return <style>{`
        .task-card{
        display:flex;
        align-items:center;
        padding-left:5px;
        padding-right:5px;
        flex-direction:row;
            border:2px solid var(--text);
            min-width:250px;
            min-height:50px;
            border-radius: 5px;
            margin-bottom:2rem;
            background-color:var(--secondary-color);
        }
    `}
    </style>
}

export default Taskcard
